class RestrictedCodeValidator(ast.NodeVisitor):
    """Validates that code only uses allowed operations"""

    ALLOWED_NAMES = {
        'print', 'len', 'range', 'str', 'int', 'float', 'list', 'dict',
        'tuple', 'set', 'bool', 'abs', 'sum', 'max', 'min', 'sorted',
        'enumerate', 'zip', 'map', 'filter'
    }

    def __init__(self):
        self.errors = []

    def visit_Import(self, node):
        self.errors.append('Imports are not allowed')
        self.generic_visit(node)

    def visit_ImportFrom(self, node):
        self.errors.append('Imports are not allowed')
        self.generic_visit(node)

    def visit_Attribute(self, node):
        self.errors.append('Attribute access is not allowed')
        self.generic_visit(node)

    def visit_Name(self, node):
        if node.id not in self.ALLOWED_NAMES and not node.id.startswith('_'):
            if isinstance(node.ctx, ast.Load):
                self.errors.append(f'Use of undefined name "{node.id}" is not allowed')
        self.generic_visit(node)

    def visit_Call(self, node):
        if isinstance(node.func, ast.Name):
            if node.func.id not in self.ALLOWED_NAMES:
                self.errors.append(f'Call to undefined function "{node.func.id}" is not allowed')
        self.generic_visit(node)


def safe_eval_code(code):
    """Safely evaluate code with restricted environment"""

    # Parse and validate code structure
    try:
        tree = ast.parse(code)
    except SyntaxError as e:
        return None, f'Syntax error: {str(e)}'

    # Validate code uses only allowed operations
    validator = RestrictedCodeValidator()
    validator.visit(tree)

    if validator.errors:
